#include <bits/stdc++.h>
#define int long long
using namespace std;
int n, p, k, a, b = 1, ans, pre = 1;
int qpow (int x, int y, int mod) {
	int res = 1;
	while (y) {
		if (y & 1) {
			res = res * x % mod;
		}
		x = x * x % mod;
		y >>= 1;
	}
	return res;
}
signed main() {
	scanf ("%lld%lld%lld", &n, &p, &k);
	for (int i = 1, a; i <= n; i++) {
		scanf ("%lld", &a);
		b = b * k % p;
		ans = (ans * a % p + b * pre % p) % p;
		pre = pre * a % p;
	}
	ans = ans * qpow (pre, p - 2, p) % p;
	printf ("%lld", ans);
	return 0;
}
